import React from 'react';
import './styles.css';

const cards = [
  { id: 1, title: 'Mountain Escape', desc: 'Discover breathtaking peaks and serene valleys.', color: '#93c5fd', imgH: '12rem' },
  { id: 2, title: 'Ocean Journey', desc: 'Explore the depths of crystal-clear waters.', color: '#6ee7b7', imgH: '12rem' },
  { id: 3, title: 'Desert Adventure', desc: 'Experience the vast golden dunes at sunset.', color: '#fca5a5', imgH: '12rem' },
];

export default function App() {
  return (
    <div style={{ display: 'flex', gap: '1.5rem', padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      {cards.map(c => (
        <div key={c.id} className="card" data-testid={c.id === 1 ? 'card' : undefined}>
          <div className="card__image-wrapper" data-testid={c.id === 1 ? 'image-wrapper' : undefined}>
            <div className="card__image" style={{ height: c.imgH, backgroundColor: c.color }} />
            <div className="card__overlay" data-testid={c.id === 1 ? 'overlay' : undefined} />
          </div>
          <div className="card__body">
            <h3 className="card__title" data-testid={c.id === 1 ? 'title' : undefined}>{c.title}</h3>
            <div className="card__bar" data-testid={c.id === 1 ? 'bar' : undefined} />
            <p className="card__desc">{c.desc}</p>
          </div>
        </div>
      ))}
    </div>
  );
}

